// =============================================================================
// 9. Adjacent cell border conflict
//    (ISO 29500-1 SS17.4.66 rule 3)
// =============================================================================

/// SS17.4.66 rule 3: When two adjacent cells have conflicting borders, the
/// border with higher weight (size * style_rank) wins.
///
/// Cell (0,0) right border: single sz=24 red (weight = 24*1 = 24)
/// Cell (0,1) left border:  single sz=4  blue (weight = 4*1 = 4)
/// The heavier border (red, sz=24) wins and is applied to both cells.
#[test]
fn spec_adjacent_cell_border_weight_resolution() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "adjacent-cell-border-conflict");
    let table = first_table(&doc);

    let cell_00 = &table.rows[0].cells[0];
    let cell_01 = &table.rows[0].cells[1];

    let right_00 = cell_00
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.right.as_ref())
        .expect("cell (0,0) should have a right border after resolution");
    let left_01 = cell_01
        .formatting
        .borders
        .as_ref()
        .and_then(|b| b.left.as_ref())
        .expect("cell (0,1) should have a left border after resolution");

    // After conflict resolution, both cells should agree on the winning border.
    assert_eq!(
        right_00.size.unwrap_or(0),
        24,
        "cell (0,0) right border should keep the heavier sz=24"
    );
    assert_eq!(
        left_01.size.unwrap_or(0),
        24,
        "cell (0,1) left border should be resolved to the heavier sz=24"
    );
    assert_eq!(
        right_00.color, left_01.color,
        "both cells should agree on the winning border color at the shared edge"
    );
}

// =============================================================================
// 10. tblLook legacy val bitmask
//     (MS-OI29500 SS17.4.55(c))
// =============================================================================

/// MS-OI29500 SS17.4.55(c): When no individual attributes are present on
/// tblLook, Word falls back to the w:val hex bitmask.
///
/// val="04A0" → firstRow=true, firstCol=true, noHBand=true, noVBand=true.
#[test]
fn spec_tbllook_legacy_bitmask_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-legacy-bitmask");
    let table = first_table(&doc);

    let tbl_look = table
        .formatting
        .tbl_look
        .as_ref()
        .expect("table should have tblLook");

    // 0x04A0 = 0b_0100_1010_0000
    // Bit fields: 0x0020=firstRow, 0x0040=lastRow, 0x0080=firstCol,
    //             0x0100=lastCol, 0x0200=noHBand, 0x0400=noVBand
    // 0x04A0 & 0x0020 = 0x0020 -> firstRow = true
    // 0x04A0 & 0x0040 = 0      -> lastRow = false
    // 0x04A0 & 0x0080 = 0x0080 -> firstCol = true
    // 0x04A0 & 0x0100 = 0      -> lastCol = false
    // 0x04A0 & 0x0200 = 0      -> noHBand = false
    // 0x04A0 & 0x0400 = 0x0400 -> noVBand = true
    assert!(
        tbl_look.first_row,
        "0x04A0 bit 0x0020: firstRow should be true"
    );
    assert!(
        !tbl_look.last_row,
        "0x04A0 bit 0x0040: lastRow should be false"
    );
    assert!(
        tbl_look.first_column,
        "0x04A0 bit 0x0080: firstCol should be true"
    );
    assert!(
        !tbl_look.last_column,
        "0x04A0 bit 0x0100: lastCol should be false"
    );
    assert!(
        !tbl_look.no_h_band,
        "0x04A0 bit 0x0200: noHBand should be false"
    );
    assert!(
        tbl_look.no_v_band,
        "0x04A0 bit 0x0400: noVBand should be true"
    );
}

/// The raw val string should be preserved for roundtrip fidelity.
#[test]
fn spec_tbllook_legacy_bitmask_val_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-legacy-bitmask");
    let table = first_table(&doc);

    let tbl_look = table.formatting.tbl_look.as_ref().unwrap();
    assert_eq!(
        tbl_look.val.as_deref(),
        Some("04A0"),
        "raw w:val should be preserved as '04A0' for roundtrip"
    );
}

/// When the legacy bitmask enables firstRow, conditional formatting from the
/// table style should apply to the first row.
#[test]
fn spec_tbllook_legacy_bitmask_firstrow_conditional_applied() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-legacy-bitmask");
    let table = first_table(&doc);

    // The table style has firstRow conditional with red shading (FF0000).
    // tblLook 0x04A0 has firstRow=true.
    let shading = table.rows[0].cells[0].formatting.shading.as_ref();
    assert!(
        shading.is_some(),
        "row 0 should have conditional shading from firstRow — \
         tblLook legacy bitmask 0x04A0 enables firstRow"
    );
    if let Some(s) = shading {
        assert_eq!(
            s.fill.as_deref(),
            Some("FF0000"),
            "row 0 should have red shading from firstRow conditional"
        );
    }
}

/// When the legacy bitmask does NOT enable lastRow, the last row should not
/// get lastRow conditional formatting.
#[test]
fn spec_tbllook_legacy_bitmask_lastrow_not_applied() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-legacy-bitmask");
    let table = first_table(&doc);

    // The table style has lastRow conditional with blue shading (0000FF).
    // tblLook 0x04A0 has lastRow=false. Last row should NOT get blue shading.
    let last_row = table.rows.len() - 1;
    let shading = table.rows[last_row].cells[0].formatting.shading.as_ref();
    if let Some(s) = shading {
        assert_ne!(
            s.fill.as_deref(),
            Some("0000FF"),
            "last row should NOT have blue shading — \
             tblLook 0x04A0 has lastRow=false, so lastRow conditional should not apply"
        );
    }
}

/// Verifies MS-OI29500 SS17.4.55(a): when tblLook is omitted, the default
/// matches bitmask 0x04A0 (firstRow=true, firstCol=true, noVBand=true,
/// noHBand=false, all others false).
#[test]
fn spec_tbllook_default_matches_ms_0x04a0() {
    let default = stemma::TblLook::default();

    // According to MS-OI29500 SS17.4.55(a), the default bitmask is 0x04A0:
    // 0x0020 = firstRow = true
    // 0x0080 = firstCol = true
    // 0x0400 = noVBand = true
    // All other bits = false (including 0x0200 noHBand)
    assert!(
        default.first_row,
        "MS default 0x04A0: firstRow should be true"
    );
    assert!(
        default.first_column,
        "MS default 0x04A0: firstColumn should be true (bit 0x0080)"
    );
    assert!(
        !default.no_h_band,
        "MS default 0x04A0: noHBand should be false (bit 0x0200 not set)"
    );
    assert!(
        default.no_v_band,
        "MS default 0x04A0: noVBand should be true"
    );
    assert!(
        !default.last_row,
        "MS default 0x04A0: lastRow should be false"
    );
    assert!(
        !default.last_column,
        "MS default 0x04A0: lastCol should be false"
    );
}

// =============================================================================
// 11. Conditional formatting border override
//     (ISO 29500-1 SS17.7.6)
// =============================================================================

/// SS17.7.6: Conditional formatting borders from tblStylePr should override
/// the table-level borders for matching cells.
///
/// Table style has thin black borders (sz=4, color=000000).
/// firstRow conditional has thick red borders (sz=12, color=FF0000).
/// First row cells should display thick red, not thin black.
#[test]
fn spec_conditional_border_override_firstrow() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-border-override");
    let table = first_table(&doc);

    // Row 0 should have conditional borders from firstRow (red sz=12)
    let cell_00_borders = table.rows[0].cells[0]
        .formatting
        .borders
        .as_ref()
        .expect("row 0 cell 0 should have borders from firstRow conditional");

    // The top border should be the firstRow conditional's red border
    let top_border = cell_00_borders
        .top
        .as_ref()
        .expect("cell (0,0) should have top border");
    assert_eq!(
        top_border.color.as_deref(),
        Some("FF0000"),
        "cell (0,0) top border should be red from firstRow conditional, \
         not black from base table style — SS17.7.6 precedence: \
         conditional formatting overrides base style"
    );
    assert_eq!(
        top_border.size,
        Some(12),
        "cell (0,0) top border size should be 12 (from firstRow conditional)"
    );
}

/// Row 1 (non-firstRow) should retain the base table style borders,
/// not the conditional firstRow borders.
///
/// Note: the top border of row 1 shares an edge with row 0's bottom border.
/// Per §17.4.66 rule 3, the heavier border (red/sz=12 from firstRow conditional)
/// wins at that shared edge. We check the bottom border instead, which is not
/// shared with a conditional row and should come from the base style.
#[test]
fn spec_conditional_border_base_style_on_non_matching_row() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-border-override");
    let table = first_table(&doc);

    // Row 1 should have the base table style borders (black sz=4)
    // unless conditional formatting replaced them.
    // Since row 1 doesn't match any conditional (noHBand=true), it should
    // have the table-level borders on non-shared edges.
    let cell_10_borders = table.rows[1].cells[0].formatting.borders.as_ref();

    // Check a non-shared edge: bottom border of the last row is the table's
    // outer bottom border, not shared with any conditional row.
    if let Some(borders) = cell_10_borders
        && let Some(bottom) = &borders.bottom
    {
        // Should be black (000000), not red (FF0000) — conditional firstRow
        // should not affect non-shared edges of non-matching rows.
        assert_ne!(
            bottom.color.as_deref(),
            Some("FF0000"),
            "row 1 cell (1,0) bottom border should NOT have firstRow conditional \
                 red border — firstRow only applies to row 0"
        );
    }
}
